/**
 * Wait for a service's /health endpoint to return 200.
 */
export async function waitForHealth(
  baseUrl: string,
  timeoutMs: number,
): Promise<boolean> {
  const deadline = Date.now() + timeoutMs;
  const healthUrl = `${baseUrl}/health`;
  while (Date.now() < deadline) {
    try {
      const ok = await httpGet(healthUrl, 5_000);
      if (ok) return true;
    } catch {
      // retry
    }
    await sleep(2_000);
  }
  return false;
}

function httpGet(url: string, timeoutMs: number): Promise<boolean> {
  return new Promise((resolve) => {
    const req = http.get(url, { timeout: timeoutMs }, (res) => {
      resolve(res.statusCode === 200);
      res.resume();
    });
    req.on('error', () => resolve(false));
    req.on('timeout', () => {
      req.destroy();
      resolve(false);
    });
  });
}

/**
 * Perform an HTTP GET and parse the JSON response body.
 */
export function httpGetJson(
  url: string,
  timeoutMs = 10_000,
): Promise<Record<string, unknown>> {
  return new Promise((resolve, reject) => {
    const req = http.get(url, { timeout: timeoutMs }, (res) => {
      const chunks: Buffer[] = [];
      res.on('data', (chunk: Buffer) => chunks.push(chunk));
      res.on('end', () => {
        try {
          const body = Buffer.concat(chunks).toString('utf-8');
          resolve(JSON.parse(body) as Record<string, unknown>);
        } catch (err) {
          reject(err);
        }
      });
    });
    req.on('error', reject);
    req.on('timeout', () => {
      req.destroy();
      reject(new Error(`HTTP GET ${url} timed out after ${timeoutMs}ms`));
    });
  });
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

const _DEPLOY_RETRIES = 3;
const _DEPLOY_RETRY_DELAY_MS = 2_000;
const _DEPLOY_REQUEST_TIMEOUT_MS = 10_000;

/**
 * Fetch a URL with retry for transient Docker networking failures.
 *
 * Retries on network errors and timeouts caused by Docker Desktop
 * TCP port-forwarding issues where the service is healthy but the
 * connection is dropped or reset.
 */
export async function fetchWithRetry(
  url: string,
  retries: number = _DEPLOY_RETRIES,
  delayMs: number = _DEPLOY_RETRY_DELAY_MS,
  timeoutMs: number = _DEPLOY_REQUEST_TIMEOUT_MS,
): Promise<Response> {
  let lastError: Error | undefined;
  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      const controller = new AbortController();
      const timer = setTimeout(() => controller.abort(), timeoutMs);
      try {
        return await fetch(url, { signal: controller.signal });
      } finally {
        clearTimeout(timer);
      }
    } catch (err) {
      lastError = err instanceof Error ? err : new Error(String(err));
      if (attempt < retries) {
        await sleep(delayMs);
      }
    }
  }
  throw lastError ?? new Error(`fetchWithRetry exhausted for ${url}`);
}

/**
 * Perform an HTTP request with retry for transient Docker networking failures.
 *
 * Supports all HTTP methods, custom headers, and request bodies.
 * Wraps fetchWithRetry with a RequestInit-like options interface.
 */
export async function httpRequest(
  url: string,
  options: {
    method?: string;
    headers?: Record<string, string>;
    body?: string;
  } = {},
): Promise<Response> {
  const init: RequestInit = {};
  if (options.method) init.method = options.method;
  if (options.headers) init.headers = options.headers;
  if (options.body) init.body = options.body;

  let lastError: Error | undefined;
  for (let attempt = 0; attempt <= _DEPLOY_RETRIES; attempt++) {
    try {
      const controller = new AbortController();
      const timer = setTimeout(() => controller.abort(), _DEPLOY_REQUEST_TIMEOUT_MS);
      try {
        return await fetch(url, { ...init, signal: controller.signal });
      } finally {
        clearTimeout(timer);
      }
    } catch (err) {
      lastError = err instanceof Error ? err : new Error(String(err));
      if (attempt < _DEPLOY_RETRIES) {
        await sleep(_DEPLOY_RETRY_DELAY_MS);
      }
    }
  }
  throw lastError ?? new Error(`httpRequest exhausted for ${url}`);
}

/**
 * Detect Docker Compose command (plugin or standalone).
 */
export function getDockerComposeCmd(): string[] {
  try {
    execSync('docker compose version', { stdio: 'pipe' });
    return ['docker', 'compose'];
  } catch {
    // fall through
  }
  try {
    execSync('docker-compose version', { stdio: 'pipe' });
    return ['docker-compose'];
  } catch {
    throw new Error(
      'Docker Compose not found. Install Docker Desktop or docker-compose.',
    );
  }
}
